import React, { useCallback, useMemo, useState } from 'react'
import isHotkey from 'is-hotkey'
import { Editable, withReact, useSlate, Slate } from 'slate-react'
import { Editor, Transforms, createEditor, Node } from 'slate'
import { withHistory } from 'slate-history'

import { Button, Icon, Toolbar } from './components';

const HOTKEYS = new Map([
  ['mod+b', 'bold'],
  ['mod+i', 'italic'],
  ['mod+u', 'underline'],
  ['mod+`', 'code'],
])

const LIST_TYPES = ['numbered-list', 'bulleted-list']

const App = () => {
  const [value, setValue] = useState<Node[]>(initialValue)
  const renderElement = useCallback(props => <Element {...props} />, [])
  const renderLeaf = useCallback(props => <Leaf {...props} />, [])
  const editor = useMemo(() => withHistory(withReact(createEditor())), [])

  return (
    <Slate editor={editor} value={value} onChange={value => setValue(value)}>
      <Toolbar>
        <MarkButton format="bold" icon="format_bold" />
        <MarkButton format="italic" icon="format_italic" />
        <MarkButton format="underline" icon="format_underlined" />
        <MarkButton format="code" icon="code" />
        <BlockButton format="heading-one" icon="looks_one" />
        <BlockButton format="heading-two" icon="looks_two" />
        <BlockButton format="block-quote" icon="format_quote" />
        <BlockButton format="numbered-list" icon="format_list_numbered" />
        <BlockButton format="bulleted-list" icon="format_list_bulleted" />
      </Toolbar>
      <Editable
        renderElement={renderElement}
        renderLeaf={renderLeaf}
        placeholder="Enter some rich text…"
        spellCheck
        autoFocus
        onKeyDown={event => {
          var hotkey: any;
          for (hotkey in HOTKEYS) {
            if (isHotkey(hotkey, event as any)) {
              event.preventDefault()
              const mark = HOTKEYS.get(hotkey);
              toggleMark(editor, mark)
            }
          }
        }}
      />
    </Slate>
  )
}

const toggleBlock = (editor: Editor, format: string) => {
  const isActive = isBlockActive(editor, format)
  const isList = LIST_TYPES.includes(format)

  Transforms.unwrapNodes(editor, {
    match: n => LIST_TYPES.includes(n.type as string),
    split: true,
  })

  Transforms.setNodes(editor, {
    type: isActive ? 'paragraph' : isList ? 'list-item' : format,
  })

  if (!isActive && isList) {
    const block = { type: format, children: [] }
    Transforms.wrapNodes(editor, block)
  }
}

const toggleMark = (editor: Editor, format: string) => {
  const isActive = isMarkActive(editor, format)

  if (isActive) {
    Editor.removeMark(editor, format)
  } else {
    Editor.addMark(editor, format, true)
  }
}

const isBlockActive = (editor: Editor, format: string) => {
  const [match] = Editor.nodes(editor, {
    match: n => n.type === format,
  }) as any;

  return !!match
}

const isMarkActive = (editor: Editor, format: string) => {
  const marks = Editor.marks(editor)
  return marks ? marks[format] === true : false
}

interface elementProps {
  attributes: any,
  children: any,
  element: any
}

const Element = (props: elementProps) => {
  switch (props.element.type) {
    case 'block-quote':
      return <blockquote {...props.attributes}>{props.children}</blockquote>
    case 'bulleted-list':
      return <ul {...props.attributes}>{props.children}</ul>
    case 'heading-one':
      return <h1 {...props.attributes}>{props.children}</h1>
    case 'heading-two':
      return <h2 {...props.attributes}>{props.children}</h2>
    case 'list-item':
      return <li {...props.attributes}>{props.children}</li>
    case 'numbered-list':
      return <ol {...props.attributes}>{props.children}</ol>
    default:
      return <p {...props.attributes}>{props.children}</p>
  }
}

interface leafProps {
  attributes: any,
  children: any,
  leaf: any
}

const Leaf = (props: leafProps) => {
  if (props.leaf.bold) {
    props.children = <strong>{props.children}</strong>
  }

  if (props.leaf.code) {
    props.children = <code>{props.children}</code>
  }

  if (props.leaf.italic) {
    props.children = <em>{props.children}</em>
  }

  if (props.leaf.underline) {
    props.children = <u>{props.children}</u>
  }

  return <span {...props.attributes}>{props.children}</span>
}

interface buttonProps {
  format: any,
  icon: any
}

const BlockButton = (props: buttonProps) => {
  const editor = useSlate()
  return (
    <Button
      active={isBlockActive(editor, props.format)}
      onMouseDown={(event: any) => {
        event.preventDefault()
        toggleBlock(editor, props.format)
      }}
    >
      <Icon>{props.icon}</Icon>
    </Button>
  )
}

const MarkButton = (props: buttonProps) => {
  const editor = useSlate()
  return (
    <Button
      active={isMarkActive(editor, props.format)}
      onMouseDown={(event: any) => {
        event.preventDefault()
        toggleMark(editor, props.format)
      }}
    >
      <Icon>{props.icon}</Icon>
    </Button>
  )
}

const initialValue = [
  {
    type: 'paragraph',
    children: [
      { text: 'This is editable ' },
      { text: 'rich', bold: true },
      { text: ' text, ' },
      { text: 'much', italic: true },
      { text: ' better than a ' },
      { text: '<textarea>', code: true },
      { text: '!' },
    ],
  },
  {
    type: 'paragraph',
    children: [
      {
        text:
          "Since it's rich text, you can do things like turn a selection of text ",
      },
      { text: 'bold', bold: true },
      {
        text:
          ', or add a semantically rendered block quote in the middle of the page, like this:',
      },
    ],
  },
  {
    type: 'block-quote',
    children: [{ text: 'A wise quote.' }],
  },
  {
    type: 'paragraph',
    children: [{ text: 'Try it out for yourself!' }],
  },
]

export default App;
